/**
 * Docker whale SVG mark for the nav rail header. Matches the Docker visual
 * identity spec path data.
 */
declare function NavRailWhaleIcon({ className }: {
    className?: string;
}): react_jsx_runtime.JSX.Element;

export { NavRail, type NavRailItem, type NavRailProps, NavRailWhaleIcon };
